// modules/tasks/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'tasks',
  description: 'Handles task creation, retrieval, and updates.',

  dependencies: { modules: ['auth'] },

  exposes: {
    routes: [
      { method: 'POST', path: '/tasks', auth: true },
      { method: 'GET', path: '/tasks/:id', auth: true },
      { method: 'PUT', path: '/tasks/bulk-update', auth: true },
    ],
    functions: ['createTask', 'getTaskById', 'bulkUpdateTasks'],
    types: ['Task', 'TaskPatch', 'TaskError'],
  },

  sideEffects: [
    'writes to: tasks table',
    'reads from: users table',
  ],

  invariants: [
    'A task must always be associated with exactly one user',
    'Bulk update must handle partial failures gracefully',
    'Transaction isolation must ensure data consistency',
  ],
});

